 * Used to assert the Actions column header contract: it must announce
 * "Actions" to screen readers while remaining visually blank. Two acceptable
 * implementations both satisfy that contract:
 *   - `<th aria-label="Actions"></th>` (aria-label is the accessible name;
 *     textContent stays empty), or
 *   - `<th><span class="visually-hidden">Actions</span></th>` (the hidden
 *     span's text is the accessible name; nothing renders visually).
 * The helpers below let the tests pin the *contract* (accessible name +
 * visually blank) rather than a single mechanism, so they pass under either.
 * ========================================================================= */

/**
 * The accessible name of an element per WAI-ARIA name computation: `aria-label`
 * first, then `aria-labelledby` (resolved against the document), then the
 * element's own text content. Mirrors what a screen reader announces.
 */
function accessibleName(el: Element): string {
  const ariaLabel = el.getAttribute('aria-label');
  if (ariaLabel !== null && ariaLabel.trim() !== '') {
    return ariaLabel.trim();
  }
  const labelledBy = el.getAttribute('aria-labelledby');
  if (labelledBy) {
    return labelledBy
      .trim()
      .split(/\s+/)
      .map((id) => (document.getElementById(id)?.textContent ?? '').trim())
      .join(' ')
      .trim();
  }
  return (el.textContent ?? '').trim();
}

/**
 * The text an element renders for a SIGHTED user: its textContent with any
 * `.visually-hidden` descendants removed. A visually-blank header is one whose
 * `visibleText` is `''` — whether it is an empty `<th>` with an `aria-label`,
 * or a `<th>` whose only text lives inside a `.visually-hidden` span.
 */
function visibleText(el: Element): string {
  const clone = el.cloneNode(true) as Element;
  for (const hidden of Array.from(clone.querySelectorAll('.visually-hidden'))) {
    hidden.remove();
  }
  return (clone.textContent ?? '').trim();
}

